#include<bits/stdc++.h>
using namespace std;
const int N=4010,M=300010;
struct edge
{
    int to,flow,nxt;
}e[M];
int s,t,tot=1,head[N],now[N],d[N];
void add1(int u,int v,int w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(int u,int v,int w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    memset(d,0,sizeof(d));
    d[s]=1;
    queue<int> q;
    q.push(s);
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=head[t];i;i=e[i].nxt)
        {
            int v=e[i].to,flow=e[i].flow;
            if(flow&&!d[v])
            {
                d[v]=d[t]+1;
                if(v==(::t))
                {
                    return true;
                }
                q.push(v);
            }
        }
    }
    return false;
}
int dfs(int x,int flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    int sum=0;
    for(int i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        int v=e[i].to,val=e[i].flow;
        if(val&&d[v]==d[x]+1)
        {
            int tmp=min(flow,dfs(v,val));
            e[i].flow-=tmp;
            e[i^1].flow+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
int dinic()
{
    int ans=0;
    while(bfs())
    {
        memcpy(now,head,sizeof(now));
        ans+=dfs(s,2e9);
    }
    return ans;
}
int n,m;
char a[101][101];
int r[101][101],D[101][101];
map<int,map<int,bool>> mp;
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%s",a[i]+1);
    }
    s=n*m*2+1;
    t=s+1;
    int tot=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)if(a[i][j]=='*')
        {
            if(j==1||a[i][j-1]=='.')
            {
                r[i][j]=++tot;
                add(s,tot,1);
            }
            else
            {
                r[i][j]=r[i][j-1];
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)if(a[i][j]=='*')
        {
            if(i==1||a[i-1][j]=='.')
            {
                D[i][j]=++tot;
                add(tot,t,1);
            }
            else
            {
                D[i][j]=D[i-1][j];
            }
            if(!mp[r[i][j]][D[i][j]])
            {
                mp[r[i][j]][D[i][j]]=true;
                add(r[i][j],D[i][j],1);
            }
        }
    }
    printf("%d",dinic());
    return 0;
}
